sql:
SELECT last_updated
   FROM cryptocurrencies
   WHERE crypto_id = 1;

external_knowledge:
- 'average daily pulse' is a metaphor for 'average percentage change in price';
- 'favored by active followers' refers to cryptocurrencies with 'active' status in the user_subscriptions table;
- 'the past week' refers to the last 7 days (pd.date >= DATE('now', '-7 days')).
